  ('optometrist-moex-01334', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '檢測眩光時，下列何種檢測儀或檢測方法不是屬於這個範疇？', '["亮度視力檢測儀（brightnessacuitytester）", "激進檢影法（radicalretinoscopy）", "米勒－納德勒眩光測試儀（Miller-Nadlerglaretester）", "多項視覺對比檢測儀（MCI8000multivisioncontrasttester）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01335', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '教導近視未矯正的低視力患者使用放大鏡時需要注意的事項，下列敘述何者正確？', '["未矯正近視的低視力患者適合把放大鏡貼近眼睛使用", "放大鏡貼近眼睛使用雖然整體倍率會下降，但可視範圍會大於放大鏡本身的直徑", "放大鏡貼近眼睛使用整體倍率會增加，且可視範圍不變", "使用的放大鏡倍率愈高，眼睛與放大鏡的距離就可以愈大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01336', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關低視力患者濾光眼鏡顏色的選擇，下列敘述何者正確？', '["白化症患者最適合使用深灰黑色的濾光眼鏡", "視網膜疾病患者適合使用黃色的濾光眼鏡", "濾光眼鏡顏色的選擇與不同病人生活的應用有最大的相關", "濾光眼鏡顏色的選擇與不同疾病有最大的相關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01337', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '在開立手持式放大鏡給予低視力患者時，也須考慮框架眼鏡的老花加入度。假設有一低視力患者的老花加 入度為+2.50D，有一手持式放大鏡的屈光度為+20.00D。此患者配戴眼鏡，再拿取放大鏡閱讀時，患者放 大鏡與眼鏡的距離為5公分，此時整體的屈光度當量為多少？', '["+20.00D", "+22.50D", "+2.50D", "+18.50D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01338', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '承上題，同一患者老花加入度為+2.50 D，使用相同屈光度為+20.00 D 的手持式放大鏡。因貼近使用放大 鏡，使得放大鏡與眼鏡的距離為0公分，此時整體的屈光度當量為多少？', '["+20.00D", "+22.50D", "+2.50D", "+18.50D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01339', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '目前臺灣輔具資源中心評估的流程為：①區公所或鄉公所申請  ②審核  ③採購  ④輔具評估  ⑤核銷', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01340', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '針對低視力病人的視力加強策略（visionenhancementoptions），下列配對何者錯誤？', '["產生問題的主因是屈光不正時，其主要的影響是投射於視網膜上的影像模糊不清，改善的策略為屈光矯 正或放大影像", "產生問題的主因是周邊視野缺損時，其主要的影響是行動障礙，改善的策略為行動訓練", "產生問題的主因是敏感度下降時，其主要的影響是對比度下降，改善的策略為加強光源、改善環境", "產生問題的主因是中樞神經病變時，其主要的影響是閱讀困難，改善的策略為屈光矯正及加強光源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01341', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關低視能者的敘述，下列何者正確？', '["低視能者由於尚有視力，並不符合領取白手杖的資格", "常用的光學輔具有放大鏡、望遠鏡、濾光眼鏡等等，可於適當時間與地點選取使用", "低視能者加上聽損及肢體平衡不良，屬多重障礙身分，若符合居家照顧資格者，不可獨自外出", "臺灣法律已針對低視能者實施領有視障證明時即吊銷駕照的規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01342', 'optometrist', 'optometrist-moex-109-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '一位 22 歲正在就讀私立大學研究所的低視能者，當他需要使用擴視機作為閱讀之用時，可透過那一個資', '["各縣市生活重建中心", "大專校院及高中職視障學生教育輔具中心", "各 縣市輔具資源中心", "長期照顧管理中心  ⑤各縣市勞工局或勞動處"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:47+00:00", "source_pdf_sha1": "0f50e66b0689", "answer_pdf_sha1": "f93bf7cc65cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
